proof_block:
// The postcondition is an implication `<big-conj> ==> r1 == r2`. Z3 cannot
// line up the two sets of ensures (one per run) because nothing forces the
// per-projection equality between r1 and r2 to be combined into the raw
// bit-vector equality used by `usize2*`.
//
// Strategy: provide `r1 == r2` as a clean conditional consequence of the
// hypothesis via `lemma_page_entry_usize_unique`, which lifts the projection
// equalities through bit_vector. Then assert the full implication so that
// the postcondition matches it syntactically.

assert(({
    &&& (usize2present(r1) == page_entry.perm.present)
    &&& (usize2ps(r1) == page_entry.perm.ps)
    &&& (usize2write(r1) == page_entry.perm.write)
    &&& (usize2execute_disable(r1) == page_entry.perm.execute_disable)
    &&& (usize2user(r1) == page_entry.perm.user)
    &&& (usize2pa(r1) == page_entry.addr)
    &&& (usize2page_entry_perm(r1) =~= page_entry.perm)
    &&& (usize2present(r2) == page_entry.perm.present)
    &&& (usize2ps(r2) == page_entry.perm.ps)
    &&& (usize2write(r2) == page_entry.perm.write)
    &&& (usize2execute_disable(r2) == page_entry.perm.execute_disable)
    &&& (usize2user(r2) == page_entry.perm.user)
    &&& (usize2pa(r2) == page_entry.addr)
    &&& (usize2page_entry_perm(r2) =~= page_entry.perm)
}) ==> det_page_entry2usize_equal(r1, r2)) by {
    if (usize2present(r1) == page_entry.perm.present)
        && (usize2ps(r1) == page_entry.perm.ps)
        && (usize2write(r1) == page_entry.perm.write)
        && (usize2execute_disable(r1) == page_entry.perm.execute_disable)
        && (usize2user(r1) == page_entry.perm.user)
        && (usize2pa(r1) == page_entry.addr)
        && (usize2present(r2) == page_entry.perm.present)
        && (usize2ps(r2) == page_entry.perm.ps)
        && (usize2write(r2) == page_entry.perm.write)
        && (usize2execute_disable(r2) == page_entry.perm.execute_disable)
        && (usize2user(r2) == page_entry.perm.user)
        && (usize2pa(r2) == page_entry.addr)
    {
        lemma_page_entry_usize_unique(r1, r2, page_entry.perm, page_entry.addr);
        assert(r1 == r2);
        assert(det_page_entry2usize_equal(r1, r2));
    }
};

helper_lemmas:
proof fn lemma_page_entry_usize_unique(r1: usize, r2: usize, perm: PageEntryPerm, addr: PAddr)
    requires
        MEM_valid(addr),
        usize2present(r1) == perm.present,
        usize2ps(r1) == perm.ps,
        usize2write(r1) == perm.write,
        usize2execute_disable(r1) == perm.execute_disable,
        usize2user(r1) == perm.user,
        usize2pa(r1) == addr,
        usize2present(r2) == perm.present,
        usize2ps(r2) == perm.ps,
        usize2write(r2) == perm.write,
        usize2execute_disable(r2) == perm.execute_disable,
        usize2user(r2) == perm.user,
        usize2pa(r2) == addr,
    ensures
        r1 == r2,
{
    // Each spec projection is `(v & MASK) != 0` (or `v & MEM_MASK` for the address).
    // The hypotheses give us the same projection value for r1 and r2, hence the
    // boolean equalities (a & MASK != 0) == (b & MASK != 0) for each single-bit
    // MASK and (a & MEM_MASK) == (b & MEM_MASK) for the address mask.
    assert((r1 & PAGE_ENTRY_PRESENT_MASK as usize != 0)
        == (r2 & PAGE_ENTRY_PRESENT_MASK as usize != 0));
    assert((r1 & PAGE_ENTRY_PS_MASK as usize != 0)
        == (r2 & PAGE_ENTRY_PS_MASK as usize != 0));
    assert((r1 & PAGE_ENTRY_WRITE_MASK as usize != 0)
        == (r2 & PAGE_ENTRY_WRITE_MASK as usize != 0));
    assert((r1 & PAGE_ENTRY_EXECUTE_MASK as usize != 0)
        == (r2 & PAGE_ENTRY_EXECUTE_MASK as usize != 0));
    assert((r1 & PAGE_ENTRY_USER_MASK as usize != 0)
        == (r2 & PAGE_ENTRY_USER_MASK as usize != 0));
    assert((r1 & MEM_MASK as usize) == (r2 & MEM_MASK as usize));

    // bit_vector combine: each single-bit mask plus MEM_MASK pin specific bits
    // of r1/r2 equal; concatenating the masks covers every bit of a `usize`,
    // so r1 == r2.
    assert(r1 == r2) by(bit_vector)
        requires
            (r1 & PAGE_ENTRY_PRESENT_MASK as usize != 0)
                == (r2 & PAGE_ENTRY_PRESENT_MASK as usize != 0),
            (r1 & PAGE_ENTRY_PS_MASK as usize != 0)
                == (r2 & PAGE_ENTRY_PS_MASK as usize != 0),
            (r1 & PAGE_ENTRY_WRITE_MASK as usize != 0)
                == (r2 & PAGE_ENTRY_WRITE_MASK as usize != 0),
            (r1 & PAGE_ENTRY_EXECUTE_MASK as usize != 0)
                == (r2 & PAGE_ENTRY_EXECUTE_MASK as usize != 0),
            (r1 & PAGE_ENTRY_USER_MASK as usize != 0)
                == (r2 & PAGE_ENTRY_USER_MASK as usize != 0),
            (r1 & MEM_MASK as usize) == (r2 & MEM_MASK as usize),
        ;
}
